section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/terraform-iac.json",
  "type": "object",
  "required": [
    "repo_layout",
    "workspaces",
    "module_sources",
    "cross_workspace_pattern",
    "refactor_method",
    "blast_radius_doc_path"
  ],
  "properties": {
    "repo_layout": {
      "type": "string",
      "description": "enum (monorepo | polyrepo)"
    },
    "workspaces": {
      "type": "array",
      "description": "array (each {env, layer, state_backend})"
    },
    "module_sources": {
      "type": "array",
      "description": "array (each registry + version)"
    },
    "cross_workspace_pattern": {
      "type": "string",
      "description": "enum (data_source | remote_state | output_consumed)"
    },
    "refactor_method": {
      "type": "string",
      "description": "enum (moved_block | import | state_rm_approved)"
    },
    "blast_radius_doc_path": {
      "type": "string",
      "description": "string (per workspace)"
    }
  }
}
